##! Geometry module - shapes, interfaces, and abstract base classes

from colors_module import Color

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    color: Color

    def __init__(self, color: Color):
        self.color = color

    @abstract
    def area(self) -> float: ...

    @abstract
    def describe(self) -> str: ...

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, color: Color, width: float, height: float):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle"

    @override
    def draw(self) -> str:
        return "Drawing rectangle"

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, color: Color, radius: float):
        super().__init__(color)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return "Circle"

    @override
    def draw(self) -> str:
        return "Drawing circle"
